// ΓöÇΓöÇΓöÇ Cost table (USD per 1M tokens) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const COST_TABLE: Record<string, { input: number; output: number }> = {
  // Groq
  "llama-3.3-70b-versatile": { input: 0.59, output: 0.79 },
  "llama-3.1-8b-instant": { input: 0.05, output: 0.08 },
  "mixtral-8x7b-32768": { input: 0.24, output: 0.24 },
  // OpenAI
  "gpt-4o": { input: 5.0, output: 15.0 },
  "gpt-4o-mini": { input: 0.15, output: 0.6 },
  o1: { input: 15.0, output: 60.0 },
  "o1-mini": { input: 1.1, output: 4.4 },
  "o3-mini": { input: 1.1, output: 4.4 },
  // Gemini
  "gemini-2.0-flash": { input: 0.1, output: 0.4 },
  "gemini-1.5-flash": { input: 0.075, output: 0.3 },
  "gemini-1.5-pro": { input: 3.5, output: 10.5 },
  // Claude
  "claude-3-5-sonnet-20241022": { input: 3.0, output: 15.0 },
  "claude-3-5-haiku-latest": { input: 0.8, output: 4.0 },
  "claude-3-opus-20240229": { input: 15.0, output: 75.0 },
  // Grok
  "grok-2-latest": { input: 2.0, output: 10.0 },
  // DeepSeek
  "deepseek-chat": { input: 0.27, output: 1.1 },
  "deepseek-reasoner": { input: 0.55, output: 2.19 },
  // Mistral
  "mistral-large-latest": { input: 2.0, output: 6.0 },
  "mistral-small-latest": { input: 0.2, output: 0.6 },
  // Cohere
  "command-r-plus-08-2024": { input: 2.5, output: 10.0 },
  "command-r-08-2024": { input: 0.15, output: 0.6 },
  // Perplexity
  sonar: { input: 1.0, output: 1.0 },
  "sonar-pro": { input: 3.0, output: 15.0 },
};

function estimateCostUSD(
  model: string,
  inputTokens: number,
  outputTokens: number
): number {
  const rates = COST_TABLE[model];
  if (!rates) return 0;
  return (rates.input * inputTokens + rates.output * outputTokens) / 1_000_000;
}

// (estimateTokens removed ΓÇö moved to base.ts)

// ΓöÇΓöÇΓöÇ Multi-key rotation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
class MultiKeyManager {
  private keys: string[];
  private cooldown = new Map<string, number>();
  private idx = 0;

  constructor(keys: string[]) {
    this.keys = [...keys];
  }

  get(): string {
    const now = Date.now();
    let bestKey = this.keys[0]!;
    let minCoolsAt = Infinity;

    for (const k of this.keys) {
      const coolsAt = this.cooldown.get(k) ?? 0;
      if (now >= coolsAt) {
        // Found a ready key ΓÇö use it and cycle index
        this.idx = (this.keys.indexOf(k) + 1) % this.keys.length;
        return k;
      }
      if (coolsAt < minCoolsAt) {
        minCoolsAt = coolsAt;
        bestKey = k;
      }
    }
    // All in cooldown ΓÇö return the one that cools soonest
    return bestKey;
  }

  markCooldown(key: string, ms = 60_000): void {
    this.cooldown.set(key, Date.now() + ms);
  }
}

// ΓöÇΓöÇΓöÇ Context window guard ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function trimMessages(messages: Message[], limit: number): Message[] {
  // Bug 11: Keep only the LAST system message (or first, but usually best to have just one)
  const allSystem = messages.filter((m) => m.role === "system");
  const system = allSystem.slice(-1); // Keep only the last one
  const rest = messages.filter((m) => m.role !== "system");
  let tokens = system.reduce((s, m) => s + estimateTokens(m.content), 0);
  const kept: Message[] = [];
  // Walk from newest to oldest
  for (let i = rest.length - 1; i >= 0; i--) {
    const t = estimateTokens(rest[i]!.content);
    if (tokens + t > limit * 0.95) break; // Slightly more buffer
    tokens += t;
    kept.unshift(rest[i]!);
  }
  return [...system, ...kept];
}

// (repairJSON and schemaToPrompt removed ΓÇö moved to base.ts)

// ΓöÇΓöÇΓöÇ Cost tracker ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
export interface CostEntry {
  model: string;
  inputTokens: number;
  outputTokens: number;
  costUSD: number;
  timestamp: number;
}

export class CostTracker {
  private _entries: CostEntry[] = [];

  record(
    model: string,
    input: string | number,
    output: string | number
  ): CostEntry {
    const inputTokens =
      typeof input === "number" ? input : estimateTokens(input);
    const outputTokens =
      typeof output === "number" ? output : estimateTokens(output);
    const costUSD = estimateCostUSD(model, inputTokens, outputTokens);
    const entry: CostEntry = {
      model,
      inputTokens,
      outputTokens,
      costUSD,
      timestamp: Date.now(),
    };
    this._entries.push(entry);
    return entry;
  }

  get totalUSD(): number {
    return this._entries.reduce((s, e) => s + e.costUSD, 0);
  }

  get entries(): CostEntry[] {
    return [...this._entries];
  }

  get summary(): { totalUSD: string; requests: number } {
    return {
      totalUSD: `$${this.totalUSD.toFixed(6)}`,
      requests: this._entries.length,
    };
  }

  reset(): void {
    this._entries = [];
  }
}

// ΓöÇΓöÇΓöÇ Abortable stream ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
export interface AbortableStream extends AsyncIterable<StreamChunk> {
  cancel(): void;
}

// ΓöÇΓöÇΓöÇ Provider factory ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function makeAdapter(
  provider: ProviderName,
  baseUrl?: string,
  azureModel?: string
): ProviderAdapter {
  switch (provider) {
    case "groq":
      return new GroqAdapter();
    case "openai":
      return new OpenAIAdapter();
    case "gemini":
      return new GeminiAdapter();
    case "anthropic":
      return new AnthropicAdapter();
    case "grok":
      return new GrokAdapter();
    case "qwen":
      return new QwenAdapter();
    case "nvidia":
      return new NvidiaAdapter();
    case "ollama":
      return new OllamaAdapter(baseUrl);
    case "mistral":
      return new MistralAdapter();
    case "deepseek":
      return new DeepSeekAdapter();
    case "cohere":
      return new CohereAdapter();
    case "together":
      return new TogetherAdapter();
    case "perplexity":
      return new PerplexityAdapter();
    case "fireworks":
      return new FireworksAdapter();
    case "cerebras":
      return new CerebrasAdapter();
    case "azure":
      return new AzureAdapter({ baseUrl: baseUrl ?? "", model: azureModel });
    case "moonshot":
      return new MoonshotAdapter();
    default:
      throw new AIError(`Unknown provider: ${provider as string}`);
  }
}

// ΓöÇΓöÇΓöÇ Fallback config ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
export interface FallbackConfig {
