export abstract class OpenAICompatAdapter implements ProviderAdapter {
  abstract readonly baseUrl: string;
  abstract readonly defaultModel: string;
  abstract readonly contextLimit: number;

  protected authHeader(apiKey: string): string {
    return `Bearer ${apiKey}`;
  }

  protected buildHeaders(apiKey: string): Record<string, string> {
    return {
      "Content-Type": "application/json",
      Authorization: this.authHeader(apiKey),
    };
  }

  protected buildBody(
    messages: Message[],
    opts: CompletionOptions | undefined,
    stream: boolean
  ): Record<string, unknown> {
    const body: Record<string, unknown> = {
      model: opts?.model ?? this.defaultModel,
      messages,
      stream,
    };
    if (opts?.temperature !== undefined) body["temperature"] = opts.temperature;
    if (opts?.maxTokens !== undefined) body["max_tokens"] = opts.maxTokens;
    if (opts?.topP !== undefined) body["top_p"] = opts.topP;
    if (opts?.stop !== undefined) body["stop"] = opts.stop;
    if (opts?.seed !== undefined) body["seed"] = opts.seed;
    if (opts?.responseFormat !== undefined)
      body["response_format"] = opts.responseFormat;
    return body;
  }

  protected endpoint(model?: string): string {
    return `${this.baseUrl}/chat/completions`;
  }

  protected async throwIfError(res: Response): Promise<void> {
    if (!res.ok) {
      let body: {
        error?: { message?: string; type?: string; code?: string | number };
      } = {};
      try {
        body = await res.json();
      } catch {
        /* ignore parse errors */
      }
      throw new AIError(body.error?.message ?? `API error ${res.status}`, {
        status: res.status,
        type: body.error?.type,
        code: body.error?.code,
      });
    }
  }

  async chat(
    messages: Message[],
    opts: CompletionOptions | undefined,
    apiKey: string
  ): Promise<string> {
    const res = await fetch(this.endpoint(opts?.model), {
      method: "POST",
      headers: this.buildHeaders(apiKey),
      body: JSON.stringify(this.buildBody(messages, opts, false)),
    });
    await this.throwIfError(res);
    const data = (await res.json()) as {
      choices: Array<{ message: { content: string } }>;
    };
    return data.choices[0]?.message?.content ?? "";
  }

  async *stream(
    messages: Message[],
    opts: CompletionOptions | undefined,
    apiKey: string,
    signal?: AbortSignal
  ): AsyncGenerator<StreamChunk, void, unknown> {
    const res = await fetch(this.endpoint(opts?.model), {
      method: "POST",
      headers: this.buildHeaders(apiKey),
      body: JSON.stringify(this.buildBody(messages, opts, true)),
      signal,
    });
    await this.throwIfError(res);
    if (!res.body) throw new AIError("Response body is null");

    for await (const raw of parseSSE(res.body, signal)) {
      try {
        const json = JSON.parse(raw) as {
          choices: Array<{
            delta: { content?: string };
            finish_reason?: string | null;
          }>;
        };
        const choice = json.choices?.[0];
        if (!choice) continue;
        yield {
          content: choice.delta?.content ?? "",
          done: choice.finish_reason != null,
          finishReason: choice.finish_reason,
        };
      } catch {
        /* ignore parse errors */
      }
    }
    // Bug 2: ensure terminal chunk even on early exit
    yield { content: "", done: true, finishReason: "end" };
  }
}

import {
  ProviderAdapter,
  Message,
  CompletionOptions,
  StreamChunk,
  AIError,
} from "./base";

export class CohereAdapter implements ProviderAdapter {
  readonly defaultModel = "command-r-plus-08-2024";
  readonly contextLimit = 128_000;
  private readonly baseUrl = "https://api.cohere.com/v2";

  private buildHeaders(apiKey: string) {
    return {
      "Content-Type": "application/json",
      Authorization: `Bearer ${apiKey}`,
    };
  }

  private buildBody(
    messages: Message[],
    opts: CompletionOptions | undefined,
    stream: boolean
  ): Record<string, unknown> {
    // Cohere v2 uses the same role names as OpenAI
    const body: Record<string, unknown> = {
      model: opts?.model ?? this.defaultModel,
      messages: messages.map((m) => ({ role: m.role, content: m.content })),
      stream,
    };
    if (opts?.temperature !== undefined) body["temperature"] = opts.temperature;
    if (opts?.maxTokens !== undefined) body["max_tokens"] = opts.maxTokens;
    if (opts?.topP !== undefined) body["p"] = opts.topP;
    if (opts?.stop !== undefined)
      body["stop_sequences"] = Array.isArray(opts.stop)
        ? opts.stop
        : [opts.stop];
    return body;
  }

  private async throwIfError(res: Response): Promise<void> {
    if (!res.ok) {
      const body = (await res.json().catch(() => ({}))) as { message?: string };
      throw new AIError(body.message ?? `Cohere API error ${res.status}`, {
        status: res.status,
      });
    }
  }

  async chat(
    messages: Message[],
    opts: CompletionOptions | undefined,
    apiKey: string
  ): Promise<string> {
    const res = await fetch(`${this.baseUrl}/chat`, {
      method: "POST",
      headers: this.buildHeaders(apiKey),
      body: JSON.stringify(this.buildBody(messages, opts, false)),
    });
    await this.throwIfError(res);

    const data = (await res.json()) as {
      message?: { content?: Array<{ type: string; text: string }> };
    };
    return data.message?.content?.find((b) => b.type === "text")?.text ?? "";
  }

  async *stream(
    messages: Message[],
    opts: CompletionOptions | undefined,
    apiKey: string,
    signal?: AbortSignal
  ): AsyncGenerator<StreamChunk, void, unknown> {
    const res = await fetch(`${this.baseUrl}/chat`, {
      method: "POST",
      headers: this.buildHeaders(apiKey),
      body: JSON.stringify(this.buildBody(messages, opts, true)),
      signal,
    });
    await this.throwIfError(res);
    if (!res.body) throw new AIError("Response body is null");

    const reader = res.body.getReader();
    const decoder = new TextDecoder("utf-8");
    let buf = "";

    try {
      while (true) {
        if (signal?.aborted) break;
        const { done, value } = await reader.read();
        if (done) break;
        buf += decoder.decode(value, { stream: true });
        const lines = buf.split(/\r?\n/);
        buf = lines.pop() ?? "";

        for (const line of lines) {
          const t = line.trim();
          if (!t) continue;
          try {
            const json = JSON.parse(t) as {
              type: string;
              delta?: { message?: { content?: { text?: string } } };
              finish_reason?: string;
            };
            if (json.type === "content-delta") {
              yield {
                content: json.delta?.message?.content?.text ?? "",
                done: false,
                finishReason: null,
              };
            } else if (json.type === "message-end") {
              yield {
                content: "",
                done: true,
                finishReason: json.finish_reason ?? "stop",
              };
            } else if (json.type === "error") {
              // Bug 6: Handle soft errors
              throw new AIError(
                (json as any).message ?? "Cohere stream error",
                {
                  type: (json as any).error_type,
                }
              );
            }
          } catch (e) {
            if (e instanceof AIError) throw e;
            /* ignore parse errors */
          }
        }
      }
    } finally {
      reader.releaseLock();
    }
  }
}

import {
  ProviderAdapter,
  Message,
  CompletionOptions,
  StreamChunk,
  AIError,
  parseSSE,
} from "./base";

type GeminiRole = "user" | "model";
interface GeminiPart {
  text: string;
}
interface GeminiContent {
  role: GeminiRole;
  parts: GeminiPart[];
}

function toGeminiContents(messages: Message[]): {
  systemInstruction?: { parts: GeminiPart[] };
  contents: GeminiContent[];
} {
  const systemMsg = messages.find((m) => m.role === "system");
  const rest = messages.filter((m) => m.role !== "system");

  const contents: GeminiContent[] = rest.map((m) => ({
    role: m.role === "assistant" ? "model" : "user",
    parts: [{ text: m.content }],
  }));

  return {
    systemInstruction: systemMsg
      ? { parts: [{ text: systemMsg.content }] }
      : undefined,
    contents,
  };
}

export class GeminiAdapter implements ProviderAdapter {
  readonly defaultModel = "gemini-2.0-flash";
  readonly contextLimit = 1_048_576;

  private endpoint(model: string, stream: boolean, apiKey: string): string {
    const action = stream ? "streamGenerateContent" : "generateContent";
    const base = "https://generativelanguage.googleapis.com/v1beta/models";
    const sse = stream ? "&alt=sse" : "";
    return `${base}/${model}:${action}?key=${apiKey}${sse}`;
  }

  private buildBody(
    messages: Message[],
    opts: CompletionOptions | undefined
  ): Record<string, unknown> {
    const { systemInstruction, contents } = toGeminiContents(messages);
    const body: Record<string, unknown> = { contents };
    if (systemInstruction) body["systemInstruction"] = systemInstruction;

    const genConfig: Record<string, unknown> = {};
    if (opts?.temperature !== undefined)
      genConfig["temperature"] = opts.temperature;
    if (opts?.maxTokens !== undefined)
      genConfig["maxOutputTokens"] = opts.maxTokens;
    if (opts?.topP !== undefined) genConfig["topP"] = opts.topP;
    if (opts?.stop !== undefined)
      genConfig["stopSequences"] = Array.isArray(opts.stop)
        ? opts.stop
        : [opts.stop];
    if (opts?.responseFormat?.type === "json_object")
      genConfig["responseMimeType"] = "application/json";

    if (Object.keys(genConfig).length > 0) body["generationConfig"] = genConfig;
    return body;
  }

  async chat(
    messages: Message[],
    opts: CompletionOptions | undefined,
    apiKey: string
  ): Promise<string> {
    const model = opts?.model ?? this.defaultModel;
    const res = await fetch(this.endpoint(model, false, apiKey), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(this.buildBody(messages, opts)),
    });

    if (!res.ok) {
      const body = (await res.json().catch(() => ({}))) as {
        error?: { message?: string };
      };
      throw new AIError(
        body.error?.message ?? `Gemini API error ${res.status}`,
        {
          status: res.status,
        }
      );
    }

    const data = (await res.json()) as {
      candidates: Array<{ content: { parts: Array<{ text: string }> } }>;
    };
    return (
      data.candidates?.[0]?.content?.parts?.map((p) => p.text).join("") ?? ""
    );
  }

  async *stream(
    messages: Message[],
    opts: CompletionOptions | undefined,
    apiKey: string,
    signal?: AbortSignal
  ): AsyncGenerator<StreamChunk, void, unknown> {
    const model = opts?.model ?? this.defaultModel;
    const res = await fetch(this.endpoint(model, true, apiKey), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(this.buildBody(messages, opts)),
      signal,
    });

    if (!res.ok) {
      const body = (await res.json().catch(() => ({}))) as {
        error?: { message?: string };
      };
      throw new AIError(
        body.error?.message ?? `Gemini API error ${res.status}`,
        {
          status: res.status,
        }
      );
    }
    if (!res.body) throw new AIError("Response body is null");

    for await (const raw of parseSSE(res.body, signal)) {
      try {
        const json = JSON.parse(raw) as {
          candidates: Array<{
            content: { parts: Array<{ text: string }> };
            finishReason?: string;
          }>;
        };
        const cand = json.candidates?.[0];
        if (!cand) continue;
        const text = cand.content?.parts?.map((p) => p.text).join("") ?? "";
        yield {
          content: text,
          done: !!cand.finishReason,
          finishReason: cand.finishReason ?? null,
        };
      } catch {}
    }
  }
}
